"use client";

import React, { createContext, useContext, useState, useEffect } from 'react';
import { JournalState, Task, Habit } from '../types/index';

const INITIAL_STATE: JournalState = {
  today: {
    date: new Date().toISOString(),
    mood: '',
    priorities: ['', '', ''],
    tasks: [],
    reminders: '',
    quickNotes: '',
    gratitude: ['', '', ''],
  },
  week: {
    goal: '',
    importantThings: ['', '', ''],
    excitedAbout: '',
  },
  habits: [
    { id: '1', name: 'Beber agua', completedDays: Array(7).fill(false) },
    { id: '2', name: 'Meditar', completedDays: Array(7).fill(false) },
    { id: '3', name: 'Ejercicio', completedDays: Array(7).fill(false) },
  ],
  devotional: {
    verse: {
      text: "Porque yo sé muy bien los planes que tengo para ustedes, afirma el Señor, planes de bienestar y no de calamidad, a fin de darles un futuro y una esperanza.",
      reference: "Jeremías 29:11"
    },
    reflection: '',
    application: '',
  },
  notes: [],
};

interface JournalContextType {
  state: JournalState;
  updateToday: (data: Partial<JournalState['today']>) => void;
  updateWeek: (data: Partial<JournalState['week']>) => void;
  toggleHabitDay: (habitId: string, dayIndex: number) => void;
  addHabit: (name: string) => void;
  updateDevotional: (data: Partial<JournalState['devotional']>) => void;
}

const JournalContext = createContext<JournalContextType | undefined>(undefined);

export const JournalProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [state, setState] = useState<JournalState>(INITIAL_STATE);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    const saved = localStorage.getItem('diario_abigail_data');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setState({ ...INITIAL_STATE, ...parsed });
      } catch (e) {
        console.error("Error parsing saved state", e);
      }
    }
  }, []);

  useEffect(() => {
    if (mounted) {
      localStorage.setItem('diario_abigail_data', JSON.stringify(state));
    }
  }, [state, mounted]);

  const updateToday = (data: Partial<JournalState['today']>) => {
    setState(prev => ({ ...prev, today: { ...prev.today, ...data } }));
  };

  const updateWeek = (data: Partial<JournalState['week']>) => {
    setState(prev => ({ ...prev, week: { ...prev.week, ...data } }));
  };

  const toggleHabitDay = (habitId: string, dayIndex: number) => {
    setState(prev => ({
      ...prev,
      habits: prev.habits.map(h => 
        h.id === habitId 
          ? { ...h, completedDays: h.completedDays.map((d, i) => i === dayIndex ? !d : d) }
          : h
      )
    }));
  };

  const addHabit = (name: string) => {
    const newHabit: Habit = {
      id: Date.now().toString(),
      name,
      completedDays: Array(7).fill(false)
    };
    setState(prev => ({ ...prev, habits: [...prev.habits, newHabit] }));
  };

  const updateDevotional = (data: Partial<JournalState['devotional']>) => {
    setState(prev => ({ ...prev, devotional: { ...prev.devotional, ...data } }));
  };

  if (!mounted) return null;

  return (
    <JournalContext.Provider value={{ state, updateToday, updateWeek, toggleHabitDay, addHabit, updateDevotional }}>
      {children}
    </JournalContext.Provider>
  );
};

export const useJournal = () => {
  const context = useContext(JournalContext);
  if (!context) throw new Error('useJournal must be used within a JournalProvider');
  return context;
};
