"use client";
import React from 'react';
import { useJournal } from '../context/JournalContext';
import { Book, Quote, Heart, PenLine } from 'lucide-react';

const Devocional: React.FC = () => {
  const { state, updateDevotional } = useJournal();
  const { devotional } = state;

  return (
    <div className="space-y-8 max-w-2xl mx-auto pb-10">
      <header className="border-b border-rose-pastel pb-4 text-center">
        <h2 className="text-3xl font-serif text-soft-text font-light italic">Mi Tiempo con Dios</h2>
        <p className="text-soft-text/60 font-medium">Reflexión y oración diaria</p>
      </header>

      {/* Versículo del día */}
      <section className="bg-white p-10 rounded-[2.5rem] journal-shadow border border-rose-pastel relative floral-pattern">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-accent-pink text-white p-3 rounded-full">
          <Book size={24} />
        </div>
        
        <div className="flex flex-col items-center text-center space-y-4">
          <Quote className="text-accent-pink/40" size={40} />
          <p className="text-xl md:text-2xl font-serif text-soft-text italic leading-relaxed">
            "{devotional.verse.text}"
          </p>
          <span className="font-bold text-deep-rose tracking-wider uppercase text-sm">
            — {devotional.verse.reference}
          </span>
        </div>
      </section>

      {/* Cajas de Reflexión y Aplicación */}
      <div className="space-y-6">
        <section className="bg-lavender-pastel/40 p-6 rounded-3xl border border-accent-lavender/30">
          <div className="flex items-center gap-2 mb-4 text-deep-rose font-medium">
            <Heart size={20} className="text-accent-pink fill-accent-pink" />
            <h3>Reflexión</h3>
          </div>
          <textarea
            value={devotional.reflection}
            onChange={(e) => updateDevotional({ reflection: e.target.value })}
            placeholder="¿Qué me dice Dios hoy a través de este versículo?"
            className="w-full h-40 bg-transparent border-none outline-none resize-none text-soft-text placeholder:italic leading-relaxed"
          />
        </section>

        <section className="bg-rose-pastel/30 p-6 rounded-3xl border border-rose-pastel/50">
          <div className="flex items-center gap-2 mb-4 text-deep-rose font-medium">
            <PenLine size={20} />
            <h3>Aplicación Personal</h3>
          </div>
          <textarea
            value={devotional.application}
            onChange={(e) => updateDevotional({ application: e.target.value })}
            placeholder="¿Cómo puedo poner esto en práctica hoy?"
            className="w-full h-40 bg-transparent border-none outline-none resize-none text-soft-text placeholder:italic leading-relaxed"
          />
        </section>
      </div>

      {/* Versículo destacado inferior */}
      <footer className="pt-6 border-t border-rose-pastel/40">
        <div className="bg-white p-6 rounded-2xl journal-shadow border border-rose-pastel/20 italic text-center text-soft-text/70 text-sm">
          "Lámpara es a mis pies tu palabra, y lumbrera a mi camino." — Salmos 119:105
        </div>
      </footer>
    </div>
  );
};

export default Devocional;
